import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.context.TestPropertySource;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class FeatureFlagService {
    @Value('${feature.new-payment-algorithm.enabled:false}')
    private boolean newAlgorithmEnabled;

    @Value('${feature.new-payment-algorithm.rollout-percentage:0}')
    private int rolloutPercentage;

    public boolean isNewAlgorithmEnabled(String userId) {
        if (!newAlgorithmEnabled) return false;
        // Consistent user-based rollout (same user always gets same experience):
        int bucket = Math.abs(userId.hashCode() % 100);
        return bucket < rolloutPercentage;  // 10% rollout: bucket 0-9 get new feature
    }
}

@Service
class PaymentProcessor {
    private final FeatureFlagService flags;
    PaymentProcessor(FeatureFlagService f) { flags = f; }

    String process(String userId, double amount) {
        if (flags.isNewAlgorithmEnabled(userId)) {
            return processWithNewAlgorithm(userId, amount);
        }
        return processWithStableAlgorithm(userId, amount);
    }
    private String processWithNewAlgorithm(String u, double a) { return 'NEW:' + u; }
    private String processWithStableAlgorithm(String u, double a) { return 'STABLE:' + u; }
}

@SpringBootTest
@TestPropertySource(properties = {
    'feature.new-payment-algorithm.enabled=true',
    'feature.new-payment-algorithm.rollout-percentage=100'
})
class FeatureFlagTest {
    @Autowired FeatureFlagService flags;
    @Autowired PaymentProcessor processor;
    @Test void flagEnabled_100percent(){
        assertTrue(flags.isNewAlgorithmEnabled('USR-001'));
        assertTrue(processor.process('USR-001',99.0).startsWith('NEW:'));
    }
}

