import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.web.reactive.server.WebTestClient;
import io.micrometer.core.instrument.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// Blue-Green YAMLs defined in k8s/blue-green/
// Service: selector {app: payment, version: blue} initially
// After smoke test: kubectl patch service → version: green

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
class BlueGreenSmokeTest {
    @Autowired WebTestClient wc;
    @Autowired MeterRegistry reg;

    @Test void health_returnsUp() {
        wc.get().uri('/actuator/health')
          .exchange()
          .expectStatus().is2xxSuccessful()
          .expectBody().jsonPath('$.status').isEqualTo('UP');
    }

    @Test void readiness_returnsUp() {
        wc.get().uri('/actuator/health/readiness')
          .exchange().expectStatus().is2xxSuccessful();
    }

    @Test void metrics_available() {
        Counter c = reg.counter('bluegreen.smoke.test');
        c.increment();
        assertTrue(c.count() >= 1.0);
    }
}

// EXPAND-CONTRACT PATTERN FOR BLUE-GREEN + DB MIGRATION
//
// PROBLEM: Rename column 'payment_ref' to 'payment_reference'
// Naive approach: rename column + deploy → v1 pods fail (can't find 'payment_reference')
// Expand-contract: 4 phases, no downtime

// PHASE 1: EXPAND (non-breaking migration)
// Flyway V5__expand_payment_ref.sql:
// ALTER TABLE payments ADD COLUMN payment_reference VARCHAR(100);
// UPDATE payments SET payment_reference = payment_ref;  -- copy data
// -- BOTH columns exist, v1 still works (reads payment_ref)
// Deploy this migration while v1 is running: SAFE

// PHASE 2: DEPLOY GREEN (reads new column, falls back to old)
// PaymentRepository.java in v2:
// String ref = entity.getPaymentReference();
// if (ref == null) ref = entity.getPaymentRef();  // fallback to old column
// v2 writes to payment_reference (new column)
// Deploy green (inactive side) — v1 still active: SAFE

// PHASE 3: SWITCH TO GREEN
// kubectl patch service payment-service -p '{...version: green}'
// v2 now active: reads new column, handles nulls from old records
// v1 (blue) still running: can rollback instantly
// Keep for 24-48 hours: verify, then move to Phase 4

// PHASE 4: CONTRACT (clean up old column)
// Flyway V6__contract_payment_ref.sql:
// ALTER TABLE payments DROP COLUMN payment_ref;
// -- Safe: no code reads payment_ref anymore (v2 reads payment_reference)
// Scale down blue (v1): it read payment_ref which no longer exists anyway

// JAVA: Dual-read entity during transition:
public class PaymentEntity {
    private String paymentReference;  // new column
    private String paymentRef;        // old column (null after Phase 4)

    public String getEffectiveRef() {
        return paymentReference != null ? paymentReference : paymentRef;
    }
}

public class ExpandContractDemo { public static void main(String[] a) {
    System.out.println("Expand-contract: 4 phases for safe DB + blue-green migration"); } }

import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.*;
import org.springframework.web.client.RestTemplate;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.context.TestPropertySource;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import org.slf4j.*;

@Service
class CanaryRollbackService {
    private static final Logger log = LoggerFactory.getLogger(CanaryRollbackService.class);
    private static final double SLO_ERROR_BUDGET = 0.001;  // 0.1%
    private static final double ROLLBACK_THRESHOLD = SLO_ERROR_BUDGET * 2;  // 0.2%

    @Value('${canary.active:false}') private boolean canaryActive;
    @Value('${canary.rollback.command:}') private String rollbackCommand;
    private final RestTemplate rest;
    CanaryRollbackService(RestTemplate r){rest=r;}

    @Scheduled(fixedRate=300_000)  // every 5 minutes
    public void monitorCanary(){
        if(!canaryActive) return;
        double errorRate = queryCanaryErrorRate();
        log.info('Canary error rate: {}%', errorRate*100);
        if(errorRate > ROLLBACK_THRESHOLD){
            log.error('CANARY ERROR RATE {}% > THRESHOLD {}% — INITIATING ROLLBACK',
                errorRate*100, ROLLBACK_THRESHOLD*100);
            rollback();
        }
    }

    double queryCanaryErrorRate() {
        // In production: query Prometheus HTTP API
        // For test: returns 0.0 (healthy canary)
        return 0.0;
    }

    void rollback() {
        // In production: exec kubectl or call k8s API
        log.error('ROLLBACK: setting canary weight to 0');
    }

    double getRollbackThreshold() { return ROLLBACK_THRESHOLD; }
}

@SpringBootTest
@TestPropertySource(properties = {'canary.active=true'})
class CanaryRollbackTest {
    @Autowired CanaryRollbackService svc;
    @Test void threshold_isCorrect() {
        assertEquals(0.002, svc.getRollbackThreshold(), 0.0001);
    }
}

import org.springframework.beans.factory.annotation.Value;
import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.web.reactive.server.WebTestClient;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.context.TestPropertySource;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import org.springframework.stereotype.Service;

// Dockerfile: multi-stage, JRE runtime, -XX:MaxRAMPercentage=75.0
// k8s: readiness /actuator/health/readiness, liveness /actuator/health/liveness
// ConfigMap: mounts application.yml
// CI: GitHub Actions test → build → deploy
// Canary: feature flag for progressive rollout

@Service
class M21DeploymentSynthesis {
    @Value('${spring.datasource.url:jdbc:h2:mem:testdb}') String dbUrl;
    @Value('${feature.canary.enabled:false}') boolean canaryEnabled;
    @Value('${feature.canary.rollout-percentage:0}') int rolloutPct;

    String getDeploymentInfo() {
        return String.format('DB=%s canary=%s pct=%d', dbUrl, canaryEnabled, rolloutPct);
    }
    boolean isCanaryForUser(String userId) {
        if(!canaryEnabled) return false;
        return Math.abs(userId.hashCode() % 100) < rolloutPct;
    }
}

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
@TestPropertySource(properties = {
    'spring.datasource.url=jdbc:h2:mem:synthesis',
    'feature.canary.enabled=true',
    'feature.canary.rollout-percentage=100'
})
class M21SynthesisTest {
    @Autowired WebTestClient wc;
    @Autowired MeterRegistry reg;
    @Autowired M21DeploymentSynthesis svc;

    @Test void healthEndpoint_returns2xx() {
        wc.get().uri('/actuator/health').exchange().expectStatus().is2xxSuccessful()
          .expectBody().jsonPath('$.status').isEqualTo('UP');
    }
    @Test void configValues_injected() {
        assertTrue(svc.getDeploymentInfo().contains('jdbc:h2:mem:synthesis'));
        assertTrue(svc.isCanaryForUser('USR-001'));
    }
    @Test void metrics_work() {
        Counter c = reg.counter('m21.synthesis', 'module', '21');
        c.increment();
        assertEquals(1.0, c.count(), 0.01);
    }
}
